def _to_snake_case(name):
    """Convert a camelCase or mixedCase flag name to snake_case."""
    if not name:
        return name

    snake_chars = []
    for char in name:
        if char.isupper():
            snake_chars.append("_")
            snake_chars.append(char.lower())
        else:
            snake_chars.append(char)
